def redact_value(value):
    """Replace a sensitive value with a redacted placeholder."""
    if value is None:
        return None
    s = str(value)
    if len(s) <= 4:
        return '***REDACTED***'
    return s[:2] + '***REDACTED***' + s[-2:]


def sanitize_headers(headers):
    """Return a dict of headers with sensitive values redacted."""
    sanitized = {}
    for key, value in headers:
        if key.lower() in SENSITIVE_HEADERS:
            sanitized[key] = '***REDACTED***'
        else:
            sanitized[key] = value
    return sanitized


def sanitize_body(data):
    """Recursively redact sensitive fields from request/response body data."""
    if data is None:
        return None
